previewCss:
.darma-loader-darma-custom-683 {
  color: var(--loader-color, #0ea5e9);
  --loader-secondary-color: #67e8f9;
  --loader-bg: #ffffff;
width: 45px;
aspect-ratio: .75;
--c: no-repeat linear-gradient(currentColor 0 0);
background:
var(--c) 0% 50%,
var(--c) 50% 50%,
var(--c) 100% 50%;
background-size: 20% 60%;
animation: darma-loader-darma-custom-683-l9 1s infinite;
}
@keyframes darma-loader-darma-custom-683-l9 {
33% {background-position: 0% 0% ,50% 100%,100% 0% }
66% {background-position: 0% 100%,50% 0% ,100% 100%}
}

